{
  "name": "Sawatdee Plan: Thai Lesson Generator",
  "description": "A comprehensive lesson plan generator tailored for foreign teachers in Thailand, aligned with the Ministry of Education (MOE) standards and the PPP teaching methodology."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface LessonPlanRequest {
  topic: string;
  gradeLevel: string;
  duration: string;
  focusArea: string;
  studentLevel: 'Beginner' | 'Intermediate' | 'Advanced';
}

export interface ProcedureStep {
  title: string;
  content: string;
  duration: string;
}

export interface LessonPlan {
  topic: string;
  strandStandards: string;
  objectives: string[];
  summary: string;
  vocabulary: string[];
  grammar: string;
  worksheetIdeas: string;
  procedure: {
    warmUp: ProcedureStep;
    presentation: ProcedureStep;
    practice: ProcedureStep;
    production: ProcedureStep;
    wrapUp: ProcedureStep;
  };
  materials: string[];
  evaluation: string;
}

export type GradeLevel = 
  | 'P1 (Prathom 1)' | 'P2 (Prathom 2)' | 'P3 (Prathom 3)' 
  | 'P4 (Prathom 4)' | 'P5 (Prathom 5)' | 'P6 (Prathom 6)'
  | 'M1 (Mattayom 1)' | 'M2 (Mattayom 2)' | 'M3 (Mattayom 3)'
  | 'M4 (Mattayom 4)' | 'M5 (Mattayom 5)' | 'M6 (Mattayom 6)';

import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, LessonPlanRequest } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const LESSON_PLAN_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    strandStandards: { 
      type: Type.STRING, 
      description: "Must reference Thai MOE strands (e.g., Strand 1: Language for Communication, Standard F1.1 Gr.3/1)" 
    },
    objectives: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING } 
    },
    summary: { type: Type.STRING },
    vocabulary: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING } 
    },
    grammar: { type: Type.STRING },
    worksheetIdeas: { type: Type.STRING, description: "Detailed description of what the student worksheet should contain" },
    procedure: {
      type: Type.OBJECT,
      properties: {
        warmUp: { 
          type: Type.OBJECT, 
          properties: { title: { type: Type.STRING }, content: { type: Type.STRING }, duration: { type: Type.STRING } },
          required: ["title", "content", "duration"]
        },
        presentation: { 
          type: Type.OBJECT, 
          properties: { title: { type: Type.STRING }, content: { type: Type.STRING }, duration: { type: Type.STRING } },
          required: ["title", "content", "duration"]
        },
        practice: { 
          type: Type.OBJECT, 
          properties: { title: { type: Type.STRING }, content: { type: Type.STRING }, duration: { type: Type.STRING } },
          required: ["title", "content", "duration"]
        },
        production: { 
          type: Type.OBJECT, 
          properties: { title: { type: Type.STRING }, content: { type: Type.STRING }, duration: { type: Type.STRING } },
          required: ["title", "content", "duration"]
        },
        wrapUp: { 
          type: Type.OBJECT, 
          properties: { title: { type: Type.STRING }, content: { type: Type.STRING }, duration: { type: Type.STRING } },
          required: ["title", "content", "duration"]
        }
      },
      required: ["warmUp", "presentation", "practice", "production", "wrapUp"]
    },
    materials: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING } 
    },
    evaluation: { type: Type.STRING }
  },
  required: [
    "topic", "strandStandards", "objectives", "summary", "vocabulary", 
    "grammar", "worksheetIdeas", "procedure", "materials", "evaluation"
  ]
};

export const generateLessonPlan = async (request: LessonPlanRequest): Promise<LessonPlan> => {
  const prompt = `
    Generate a highly professional ESL/EFL lesson plan for a foreign teacher working in Thailand.

    Topic: ${request.topic}
    Grade Level: ${request.gradeLevel}
    Student Ability: ${request.studentLevel}
    Duration: ${request.duration} minutes
    Language Focus: ${request.focusArea}

    IMPORTANT: 
    1. The "strandStandards" must strictly follow the Thai Ministry of Education (MOE) Basic Education Core Curriculum (BECC 2008). 
       Examples: "Standard F1.1: Understanding of and capacity to interpret what has been heard and read from various types of media, and ability to express opinions with proper reasoning."
    2. Use the PPP (Presentation, Practice, Production) methodology.
    3. Ensure the vocabulary and grammar are age-appropriate for ${request.gradeLevel} in the Thai context.
    4. Provide clear, actionable steps for the teacher.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: LESSON_PLAN_SCHEMA,
      }
    });

    if (!response.text) {
      throw new Error("Failed to generate content from Gemini");
    }

    return JSON.parse(response.text) as LessonPlan;
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

import React from 'react';
import { LessonPlanRequest, GradeLevel } from '../types';

interface Props {
  onGenerate: (data: LessonPlanRequest) => void;
  isLoading: boolean;
}

export const LessonPlanForm: React.FC<Props> = ({ onGenerate, isLoading }) => {
  const [formData, setFormData] = React.useState<LessonPlanRequest>({
    topic: '',
    gradeLevel: 'P1 (Prathom 1)',
    duration: '60',
    focusArea: 'Speaking & Listening',
    studentLevel: 'Beginner',
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onGenerate(formData);
  };

  const gradeLevels: GradeLevel[] = [
    'P1 (Prathom 1)', 'P2 (Prathom 2)', 'P3 (Prathom 3)', 
    'P4 (Prathom 4)', 'P5 (Prathom 5)', 'P6 (Prathom 6)',
    'M1 (Mattayom 1)', 'M2 (Mattayom 2)', 'M3 (Mattayom 3)',
    'M4 (Mattayom 4)', 'M5 (Mattayom 5)', 'M6 (Mattayom 6)'
  ];

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 md:p-8 space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="text-sm font-semibold text-gray-700 block">Lesson Topic / Theme</label>
          <input
            type="text"
            required
            value={formData.topic}
            onChange={(e) => setFormData({ ...formData, topic: e.target.value })}
            placeholder="e.g., Daily Routines, At the Zoo..."
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition"
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-semibold text-gray-700 block">Grade Level (Thai System)</label>
          <select
            value={formData.gradeLevel}
            onChange={(e) => setFormData({ ...formData, gradeLevel: e.target.value as GradeLevel })}
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition"
          >
            {gradeLevels.map((level) => (
              <option key={level} value={level}>{level}</option>
            ))}
          </select>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-semibold text-gray-700 block">Duration (Minutes)</label>
          <input
            type="number"
            required
            value={formData.duration}
            onChange={(e) => setFormData({ ...formData, duration: e.target.value })}
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition"
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-semibold text-gray-700 block">Main Focus</label>
          <select
            value={formData.focusArea}
            onChange={(e) => setFormData({ ...formData, focusArea: e.target.value })}
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition"
          >
            <option>Speaking & Listening</option>
            <option>Reading & Writing</option>
            <option>Integrated Skills</option>
            <option>Grammar & Vocabulary</option>
            <option>Phonics / Pronunciation</option>
          </select>
        </div>

        <div className="space-y-2 md:col-span-2">
          <label className="text-sm font-semibold text-gray-700 block">Student Ability Level</label>
          <div className="flex space-x-4">
            {(['Beginner', 'Intermediate', 'Advanced'] as const).map((level) => (
              <button
                key={level}
                type="button"
                onClick={() => setFormData({ ...formData, studentLevel: level })}
                className={`flex-1 py-3 px-4 rounded-xl border transition font-medium ${
                  formData.studentLevel === level
                    ? 'bg-indigo-50 border-indigo-500 text-indigo-700 ring-1 ring-indigo-500'
                    : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'
                }`}
              >
                {level}
              </button>
            ))}
          </div>
        </div>
      </div>

      <button
        type="submit"
        disabled={isLoading}
        className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition transform hover:-translate-y-0.5 active:translate-y-0 flex items-center justify-center space-x-2 ${
          isLoading ? 'bg-indigo-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700'
        }`}
      >
        {isLoading ? (
          <>
            <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
            <span>Drafting Lesson Plan...</span>
          </>
        ) : (
          <>
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M11.3 1.047a1 1 0 01.897.95V4h2.803a1 1 0 01.95.697l2.197 7.14a1 1 0 01-.95 1.163H15.5V17a2 2 0 01-2 2h-3a2 2 0 01-2-2v-3.5h-1a1 1 0 01-1-1v-4a1 1 0 011-1h1V4a1 1 0 01.95-.697l2.197-2.197a1 1 0 01.95-.06zM13.5 13h2.1l-1.54-5H13.5v5z" clipRule="evenodd" />
            </svg>
            <span>Generate Professional Lesson Plan</span>
          </>
        )}
      </button>
    </form>
  );
};

import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { LessonPlanForm } from './components/LessonPlanForm';
import { LessonPlanView } from './components/LessonPlanView';
import { generateLessonPlan } from './services/geminiService';
import { LessonPlan, LessonPlanRequest } from './types';

const App: React.FC = () => {
  const [lessonPlan, setLessonPlan] = useState<LessonPlan | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (data: LessonPlanRequest) => {
    setIsLoading(true);
    setError(null);
    setLessonPlan(null); // Clear previous plan
    try {
      const plan = await generateLessonPlan(data);
      setLessonPlan(plan);
      // Scroll to result on mobile
      setTimeout(() => {
        const resultEl = document.getElementById('lesson-plan-result');
        if (resultEl) resultEl.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err: any) {
      setError(err.message || "Something went wrong while generating the lesson plan. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Layout>
      <div className="max-w-5xl mx-auto space-y-12">
        <section className="text-center space-y-4">
          <div className="inline-block px-4 py-1.5 bg-indigo-100 text-indigo-700 rounded-full text-xs font-bold uppercase tracking-widest mb-2">
            AI-Powered Education
          </div>
          <h1 className="text-4xl md:text-5xl font-black text-gray-900 tracking-tight">
            Lesson Plans for <span className="text-indigo-600">Thailand</span>.
          </h1>
          <p className="text-gray-500 text-lg md:text-xl max-w-2xl mx-auto font-medium">
            Generate standard-aligned, Ministry of Education compliant lesson plans in seconds. Tailored for foreign language teachers.
          </p>
        </section>

        <section id="generator-form">
          <LessonPlanForm onGenerate={handleGenerate} isLoading={isLoading} />
        </section>

        {error && (
          <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-xl flex items-start space-x-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            <div>
              <p className="text-red-700 font-bold">Generation Error</p>
              <p className="text-red-600 text-sm">{error}</p>
            </div>
          </div>
        )}

        <div id="lesson-plan-result">
          {lessonPlan && <LessonPlanView plan={lessonPlan} />}
        </div>

        {!lessonPlan && !isLoading && (
          <div className="text-center py-20 bg-gray-50 rounded-3xl border-2 border-dashed border-gray-200">
            <div className="flex flex-col items-center justify-center text-gray-400">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
              </svg>
              <p className="font-medium">No lesson plan generated yet.</p>
              <p className="text-sm">Fill out the form above to start your planning.</p>
            </div>
          </div>
        )}
      </div>
    </Layout>
  );
};

export default App;
